def linear_svm_sgd(X, y, C=1.0, lr=0.01, epochs=500, seed=0):
    """
    X: feature matrix; y: labels in {-1, +1}
    Returns weight vector w (no bias for simplicity).
    """
    import random; random.seed(seed)
    n, d = len(X), len(X[0])
    w    = [0.0] * d

    for epoch in range(1, epochs+1):
        eta = lr / epoch  # decreasing learning rate
        for i in range(n):
            score = sum(w[j]*X[i][j] for j in range(d))
            if y[i] * score < 1:  # inside or wrong side of margin
                for j in range(d):
                    w[j] = w[j] * (1 - eta) + ___________  # regularise + hinge gradient
            else:
                for j in range(d):
                    w[j] *= (1 - eta)  # only regularise
    return w

def predict_svm(X, w):
    return [1 if sum(w[j]*x[j] for j in range(len(w))) >= 0 else -1 for x in X]
